function transformVector(
  inputVector: [number, number, number],
  transformationMatrix: number[][],
  outputVector: [number, number, number]
): void {
  for (let componentIndex = 0; componentIndex < 3; componentIndex++) {
    outputVector[componentIndex] = 0;
    for (let matrixColumn = 0; matrixColumn < 3; matrixColumn++) {
      outputVector[componentIndex] +=
        transformationMatrix[componentIndex][matrixColumn] *
        inputVector[matrixColumn];
    }
  }
}
